<div class="d-flex justify-content-between mb-2"><h1 class="h5">Cotizaciones</h1><a href="/app/cotizaciones/crear" class="btn btn-primary btn-sm">Nueva cotización</a></div><table class="table table-sm"><thead><tr><th>Número</th><th>Cliente</th><th>Emisión</th><th>Vencimiento</th><th>Total</th><th>Estado</th></tr></thead><tbody><?php foreach($cotizaciones as $c): ?><tr><td><?= e($c['numero']) ?></td><td><?= e($c['cliente']) ?></td><td><?= e($c['fecha_emision']) ?></td><td><?= e($c['fecha_vencimiento']) ?></td><td>$<?= number_format((float)$c['total'],2) ?></td><td><span class="badge text-bg-light"><?= e($c['estado']) ?></span></td></tr><?php endforeach; ?></tbody></table>
